=<!DOCTYPE html>
<html lang="fr">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Trends Social Media - {{ $('Loop Over TikTok Queries').first().json.Query }}</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            line-height: 1.6;
            color: #333;
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            min-height: 100vh;
            padding: 20px;
        }

        .newsletter-container {
            max-width: 1200px;
            margin: 0 auto;
            background: white;
            border-radius: 20px;
            overflow: hidden;
            box-shadow: 0 20px 40px rgba(0,0,0,0.1);
        }

        .header {
            background: linear-gradient(135deg, #ff6b6b, #ee5a24);
            color: white;
            padding: 40px 30px;
            text-align: center;
        }

        .header h1 {
            font-size: 2.8em;
            margin-bottom: 10px;
            font-weight: 700;
        }

        .header p {
            font-size: 1.2em;
            opacity: 0.9;
            margin-bottom: 15px;
        }

        .keyword-badge {
            display: inline-block;
            background: rgba(255,255,255,0.2);
            color: white;
            padding: 8px 20px;
            border-radius: 20px;
            font-size: 1em;
            font-weight: 600;
            backdrop-filter: blur(10px);
        }

        .stats-overview {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
            gap: 20px;
            padding: 30px;
            background: #f8f9fa;
        }

        .stat-card {
            background: white;
            padding: 20px;
            border-radius: 15px;
            text-align: center;
            box-shadow: 0 5px 15px rgba(0,0,0,0.08);
            border-left: 4px solid;
        }

        .stat-card.high { border-left-color: #ff4757; }
        .stat-card.medium { border-left-color: #ffa502; }
        .stat-card.low { border-left-color: #70a1ff; }

        .stat-number {
            font-size: 2.5em;
            font-weight: bold;
            margin-bottom: 5px;
        }

        .stat-label {
            color: #666;
            font-size: 0.9em;
            text-transform: uppercase;
            letter-spacing: 1px;
        }

        .table-container {
            margin: 30px;
            background: white;
            border-radius: 15px;
            overflow: hidden;
            box-shadow: 0 10px 25px rgba(0,0,0,0.1);
        }

        .table-header {
            background: linear-gradient(135deg, #2c3e50, #34495e);
            color: white;
            padding: 25px 30px;
            text-align: center;
        }

        .table-title {
            font-size: 1.8em;
            font-weight: 600;
            margin-bottom: 5px;
        }

        .table-subtitle {
            opacity: 0.8;
            font-size: 1em;
        }

        .trends-table {
            width: 100%;
            border-collapse: collapse;
            font-size: 0.95em;
        }

        .trends-table th {
            background: #f8f9fa;
            padding: 15px 12px;
            text-align: left;
            font-weight: 600;
            color: #555;
            border-bottom: 2px solid #dee2e6;
            text-transform: uppercase;
            font-size: 0.8em;
            letter-spacing: 0.5px;
        }

        .trends-table td {
            padding: 15px 12px;
            border-bottom: 1px solid #eee;
            vertical-align: middle;
            text-align: center;
        }

        .trends-table td:nth-child(3),
        .trends-table td:nth-child(4) {
            text-align: left;
        }

        .trends-table tr:nth-child(even) {
            background-color: #f8f9fa;
        }

        .trends-table tr:hover {
            background-color: #e3f2fd;
            transform: scale(1.01);
            transition: all 0.2s ease;
        }

        .rank-number {
            font-weight: bold;
            font-size: 1.2em;
            color: #2c3e50;
        }

        .rank-number.top3 {
            color: #ff6b6b;
            font-size: 1.4em;
        }

        .source-badge {
            padding: 6px 12px;
            border-radius: 20px;
            font-size: 0.8em;
            font-weight: 600;
            text-transform: uppercase;
            letter-spacing: 0.5px;
        }

        .source-badge.tiktok {
            background: #ff0050;
            color: white;
        }

        .source-badge.reddit {
            background: #ff4500;
            color: white;
        }

        .source-badge.instagram {
            background: #e4405f;
            color: white;
        }

        .level-badge {
            padding: 4px 10px;
            border-radius: 15px;
            font-size: 0.75em;
            font-weight: 600;
            text-transform: uppercase;
        }

        .level-badge.high {
            background: #ff4757;
            color: white;
        }

        .level-badge.medium {
            background: #ffa502;
            color: white;
        }

        .level-badge.low {
            background: #70a1ff;
            color: white;
        }

        .content-text {
            max-width: 250px;
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
            color: #555;
            line-height: 1.4;
        }

        .author-link {
            color: #667eea;
            text-decoration: none;
            font-weight: 600;
        }

        .author-link:hover {
            text-decoration: underline;
        }

        .score-number {
            font-weight: bold;
            color: #2c3e50;
            font-size: 1.1em;
        }

        .footer {
            text-align: center;
            padding: 30px;
            background: #f8f9fa;
            color: #666;
            border-top: 1px solid #eee;
        }

        .footer p {
            margin-bottom: 10px;
        }

        .date-info {
            font-size: 0.9em;
            color: #888;
        }

        @media (max-width: 768px) {
            .newsletter-container {
                margin: 10px;
                border-radius: 15px;
            }

            .header {
                padding: 30px 20px;
            }

            .header h1 {
                font-size: 2.2em;
            }

            .table-container {
                margin: 20px;
                overflow-x: auto;
            }

            .trends-table {
                min-width: 800px;
            }

            .stats-overview {
                padding: 20px;
                grid-template-columns: 1fr;
            }
        }
    </style>
</head>
<body>
    <div class="newsletter-container">
        <!-- Header -->
        <header class="header">
            <h1>📊 Récapitulatif par Hashtag</h1>
            <p>Scores totaux par réseau social</p>
        </header>

        <!-- Hashtag Summary Table -->
        <section class="table-container" style="margin: 30px 30px 0 30px;">
            <table class="trends-table">
                <thead>
                    <tr>
                        <th>Hashtag</th>
                        <th>TikTok</th>
                        <th>Reddit</th>
                        <th>Instagram</th>
                        <th>Score Total</th>
                    </tr>
                </thead>
                <tbody>
                    <tr>
                        <td>
                            <span style="font-weight: bold; color: #ff6b6b; font-size: 1.1em;">#{{ $('Loop Over TikTok Queries').first().json.Query }}</span>
                        </td>
                        <td>
                            <span class="score-number">{{ $('Rank TikTok Posts1').all().filter(item => item.json.source === 'TikTok').reduce((sum, item) => sum + item.json.score, 0).toLocaleString('fr-FR') }}</span>
                        </td>
                        <td>
                            <span class="score-number">{{ $('Rank TikTok Posts1').all().filter(item => item.json.source === 'Reddit').reduce((sum, item) => sum + item.json.score, 0).toLocaleString('fr-FR') }}</span>
                        </td>
                        <td>
                            <span class="score-number">{{ $('Rank TikTok Posts1').all().filter(item => item.json.source === 'Instagram').reduce((sum, item) => sum + item.json.score, 0).toLocaleString('fr-FR') }}</span>
                        </td>
                        <td>
                            <span class="score-number" style="color: #ff6b6b; font-size: 1.2em;">{{ $('Rank TikTok Posts1').all().reduce((sum, item) => sum + item.json.score, 0).toLocaleString('fr-FR') }}</span>
                        </td>
                    </tr>
                </tbody>
            </table>
        </section>

        <!-- Main Table -->
        <section class="table-container">
            <div class="table-header">
                <div class="table-title">#{{ $('Loop Over TikTok Queries').first().json.Query }}</div>
                <div class="table-subtitle"></div>
            </div>

            <table class="trends-table">
                <thead>
                    <tr>
                        <th>Rang</th>
                        <th>Source</th>
                        <th>Auteur</th>
                        <th>Contenu</th>
                        <th>Score</th>
                        <th>Level</th>
                    </tr>
                </thead>
                <tbody>
                    {{ $('Rank TikTok Posts1').all().map(item => `
                        <tr onclick="window.open('${item.json.url}', '_blank')" style="cursor: pointer;">
                            <td>
                                <span class="rank-number ${item.json.rank <= 3 ? 'top3' : ''}">${item.json.rank}</span>
                            </td>
                            <td>
                                <span class="source-badge ${item.json.source.toLowerCase()}">${item.json.source}</span>
                            </td>
                            <td>
                                <a href="${item.json.url}" target="_blank" class="author-link">${item.json.author}</a>
                            </td>
                            <td>
                                <div class="content-text" title="${item.json.content}">${item.json.content}</div>
                            </td>
                            <td>
                                <span class="score-number">${item.json.score.toLocaleString('fr-FR')}</span>
                            </td>
                            <td>
                                <span class="level-badge ${item.json.level.toLowerCase()}">${item.json.level}</span>
                            </td>
