                    `).join('') }}
                </tbody>
            </table>
        </section>

        <!-- Footer -->
        <footer class="footer">
            <p><strong>Social Media Trends Dashboard</strong></p>
            <p>Analyse automatisée des contenus par mot-clé</p>
            <div class="date-info">
                <p>Généré le {{ new Date().toLocaleDateString('fr-FR', { 
                    year: 'numeric', 
                    month: 'long', 
                    day: 'numeric', 
                    hour: '2-digit', 
                    minute: '2-digit' 
                }) }}</p>
            </div>
        </footer>
    </div>
</body>
</html>

