// Code pour nœud Code n8n - Classement TikTok avec score personnalisé
// Récupérer les données d'entrée
const items = $input.all();

// Vérifier si on a des données
if (!items || items.length === 0) {
  console.log("❌ Aucune donnée d'entrée trouvée");
  return [];
}

// Extraire les posts TikTok du JSON
let posts = [];

// Si les données sont dans un tableau à l'intérieur du premier item
if (items[0] && items[0].json && Array.isArray(items[0].json)) {
  posts = items[0].json;
} 
// Si les données sont directement dans les items
else if (Array.isArray(items)) {
  posts = items.map(item => item.json);
}

console.log(`📥 ${posts.length} posts TikTok trouvés`);

// Calculer le score pour chaque post TikTok
const postsWithScore = posts.map((post, index) => {
  // Métriques TikTok
  const likes = post.diggCount || 0;
  const comments = post.commentCount || 0;
  const shares = post.shareCount || 0;
  const views = post.playCount || 0;

  // Calcul du score : (likes * 1) + (comments * 2) + (shares * 3) + (views / 1000)
  const likesScore = likes * 1;
  const commentsScore = comments * 2;
  const sharesScore = shares * 3;
  const viewsScore = Math.floor(views / 1000);
  const totalScore = likesScore + commentsScore + sharesScore + viewsScore;

  return {
    json: {
      url: post.webVideoUrl || `https://www.tiktok.com/@${post.authorMeta?.name}/video/${post.id}`,
      caption: post.text || "Pas de caption",
      score: totalScore,
      // Données détaillées pour debug (optionnel)
      details: {
        likes: likes,
        comments: comments,
        shares: shares,
        views: views,
        author: post.authorMeta?.name || "Inconnu",
        id: post.id
      }
    }
  };
}).filter(post => post.json.url); // Filtrer les posts sans URL

console.log(`✅ ${postsWithScore.length} posts traités avec succès`);

// Trier par score décroissant
const sortedPosts = postsWithScore.sort((a, b) => b.json.score - a.json.score);

// Prendre les 10 meilleurs
const topPosts = sortedPosts.slice(0, 10);

// Ajouter un rang à chaque post
const rankedPosts = topPosts.map((post, index) => ({
  json: {
    rank: index + 1,
    url: post.json.url,
    caption: post.json.caption,
    score: post.json.score
  }
}));

// Retourner les résultats avec le format demandé : url, caption, score
return rankedPosts;

// Code pour nœud Code n8n - Classement TikTok
// Récupérer le keyword dynamiquement
const keyword = $('Loop Over TikTok Queries').first().json.Query;

// Récupérer les données du nœud précédent
const tiktokData = $('Score and Sort TikTok Posts').all();

// Fonction pour déterminer le level basé sur le score
function getLevel(score) {
  if (score >= 10000) return 'High';
  if (score >= 1000) return 'Medium';
  return 'Low';
}

// Fonction pour extraire l'auteur TikTok
function getAuthor(item) {
  const tiktokMatch = item.url.match(/tiktok\.com\/@([^\/]+)/);
  return tiktokMatch ? `@${tiktokMatch[1]}` : '@inconnu';
}

// Transformer les données TikTok
const tiktokPosts = tiktokData.map(item => ({
  json: {
    source: 'TikTok',
    keyword: keyword,
    author: getAuthor(item.json),
    content: (item.json.caption || 'Pas de caption').substring(0, 50) + '...',
    score: item.json.score,
    level: getLevel(item.json.score),
    url: item.json.url,
    originalRank: item.json.rank
  }
}));

// Trier par score décroissant
const sortedPosts = tiktokPosts.sort((a, b) => b.json.score - a.json.score);

// Ajouter le rang
const rankedPosts = sortedPosts.map((post, index) => ({
  json: {
    ...post.json,
    rank: index + 1,
    date: new Date().toISOString().split('T')[0]
  }
}));

// Prendre le top 15
const topPosts = rankedPosts.slice(0, 15);

return topPosts;
